//	    SourceLinkSourceableOnPost(post.ApprovedEQ(true)),
//	).All(ctx)
func SourceLinkSourceableOnPost(preds ...predicate.Post) predicate.SourceLink {
	return predicate.SourceLink(func(s *sql.Selector) {
		sub := sql.Select(post.FieldID).From(sql.Table(post.Table))
		for _, p := range preds {
			p(sub)
		}
		s.Where(sql.And(
			sql.EQ(s.C(sourcelink.FieldSourceableType), string(PostMorphKey)),
			sql.In(s.C(sourcelink.FieldSourceableID), sub),
		))
	})
}

