// QuerySourceable resolves the polymorphic parent of this SourceLink
// and returns it through the sealed-interface return type. The caller
// type-switches on the result to recover the concrete parent — only the
// types listed in MorphTo's AllowedTypes are possible branches.
//
// Laravel equivalent:
//
//	$commentable = $comment->commentable;  // Post | Video | null
//
// entpoly:
//
//	parent, err := comment.QuerySourceable(ctx)
//	if err != nil { return err }
//	switch p := parent.(type) {
//	case *Post:
//	    // use p as *Post
//	case *Video:
//	    // use p as *Video
//	case nil:
//	    // no parent set
//	}
//
// Returns (nil, nil) when the discriminator pair is unset. Returns a
// typed error when the persisted morph type is not in the allowed set
// (e.g. data written by a different schema version or a bypass via raw
// SQL despite the DB enum constraint).
func (c *SourceLink) QuerySourceable(ctx context.Context) (SourceLinkSourceableParent, error) {
	if c.SourceableID == nil || c.SourceableType == nil {
		return nil, nil
	}
	switch *c.SourceableType {
	case string(PostMorphKey):
		id, err := strconv.Atoi(*c.SourceableID)
		if err != nil {
			return nil, fmt.Errorf("entpoly: parse Post id %q: %w", *c.SourceableID, err)
		}
		return NewPostClient(c.config).Get(ctx, id)
	case string(VideoMorphKey):
		id, err := strconv.Atoi(*c.SourceableID)
		if err != nil {
			return nil, fmt.Errorf("entpoly: parse Video id %q: %w", *c.SourceableID, err)
		}
		return NewVideoClient(c.config).Get(ctx, id)
	default:
		return nil, fmt.Errorf("entpoly: unknown morph type %q for SourceLink.sourceable", *c.SourceableType)
	}
}

