// BookmarkPinnableLoader is the ent-native chainable
// eager-load object returned by (BookmarkQuery).WithPinnable().
// Call .All(ctx) on it to run the batched query and receive a typed
// result. Mirrors ent's standard .WithX().All(ctx) idiom.
type BookmarkPinnableLoader struct {
	q *BookmarkQuery
}

// WithPinnable returns the typed eager-load chain for this query.
// Use over plain .All(ctx) on any list-page path to avoid the N+1
// problem inherent to per-row QueryPinnable(ctx) calls.
//
//	r, err := client.Bookmark.Query().Limit(50).WithPinnable().All(ctx)
//	for _, child := range r.Bookmarks {
//	    parent := r.Pinnable[child.ID]
//	    switch p := parent.(type) {
//	    case *Post: // typed *Post
//	    case *Video: // typed *Video
//	    case nil: // discriminator unset on this row
//	    }
//	}
//
// Total queries: 1 (children) + N (distinct parent types in the
// batch). Compared to lazy resolution via QueryPinnable(ctx),
// which fires one parent query PER child, this is the standard
// N+1 fix.
func (q *BookmarkQuery) WithPinnable() *BookmarkPinnableLoader {
	return &BookmarkPinnableLoader{q: q}
}

// All runs the Bookmark query and eager-loads every row's
// polymorphic "pinnable" parent in batched per-type queries.
func (l *BookmarkPinnableLoader) All(ctx context.Context) (*BookmarkPinnablePreloadResult, error) {
	children, err := l.q.All(ctx)
	if err != nil {
		return nil, err
	}
	result := &BookmarkPinnablePreloadResult{
		Bookmarks: children,
		Pinnable:  make(map[int]BookmarkPinnableParent, len(children)),
	}
	if len(children) == 0 {
		return result, nil
	}

	// Per-parent-type buckets — collect both the child→childlist map
	// (so we can attach the loaded parent back to every child) and
	// the list of parent IDs to feed the batched IN(...) query.
	var postIDs []int
	postToChildren := map[int][]*Bookmark{}
	var videoIDs []int
	videoToChildren := map[int][]*Bookmark{}

	for _, ch := range children {
		if ch.PinnableID == nil || ch.PinnableType == nil {
			continue
		}
		switch *ch.PinnableType {
		case string(PostMorphKey):
			pid, perr := strconv.Atoi(*ch.PinnableID)
			if perr != nil {
				return nil, fmt.Errorf("entpoly: AllWithPinnable: parse Post id %q: %w", *ch.PinnableID, perr)
			}
			postIDs = append(postIDs, pid)
			postToChildren[pid] = append(postToChildren[pid], ch)
		case string(VideoMorphKey):
			pid, perr := strconv.Atoi(*ch.PinnableID)
			if perr != nil {
				return nil, fmt.Errorf("entpoly: AllWithPinnable: parse Video id %q: %w", *ch.PinnableID, perr)
			}
			videoIDs = append(videoIDs, pid)
			videoToChildren[pid] = append(videoToChildren[pid], ch)
		}
	}
	if len(postIDs) > 0 {
		parents, perr := NewPostClient(l.q.config).Query().
			Where(post.IDIn(postIDs...)).
			All(ctx)
		if perr != nil {
			return nil, fmt.Errorf("entpoly: AllWithPinnable: batch-load Post: %w", perr)
		}
		for _, p := range parents {
			for _, ch := range postToChildren[p.ID] {
				result.Pinnable[ch.ID] = p
			}
		}
	}
	if len(videoIDs) > 0 {
		parents, perr := NewVideoClient(l.q.config).Query().
			Where(video.IDIn(videoIDs...)).
			All(ctx)
		if perr != nil {
			return nil, fmt.Errorf("entpoly: AllWithPinnable: batch-load Video: %w", perr)
		}
		for _, p := range parents {
			for _, ch := range videoToChildren[p.ID] {
				result.Pinnable[ch.ID] = p
			}
		}
	}

	return result, nil
}

